import 'dart:convert';

Package packageFromJson(String str) => Package.fromJson(json.decode(str));

String packageToJson(Package data) => json.encode(data.toJson());

class Package {
    String name;
    String description;
    String homepage;
    String main;
    String types;
    String module;
    Exports exports;
    String version;
    Engines engines;
    List<Maintainer> maintainers;
    Repository repository;
    String license;
    Scripts scripts;
    Bin bin;

    Package({
        required this.name,
        required this.description,
        required this.homepage,
        required this.main,
        required this.types,
        required this.module,
        required this.exports,
        required this.version,
        required this.engines,
        required this.maintainers,
        required this.repository,
        required this.license,
        required this.scripts,
        required this.bin,
    });

    factory Package.fromJson(Map<String, dynamic> json) => Package(
        name: json["name"],
        description: json["description"],
        homepage: json["homepage"],
        main: json["main"],
        types: json["types"],
        module: json["module"],
        exports: Exports.fromJson(json["exports"]),
        version: json["version"],
        engines: Engines.fromJson(json["engines"]),
        maintainers: List<Maintainer>.from(json["maintainers"].map((x) => Maintainer.fromJson(x))),
        repository: Repository.fromJson(json["repository"]),
        license: json["license"],
        scripts: Scripts.fromJson(json["scripts"]),
        bin: Bin.fromJson(json["bin"]),
    );

    Map<String, dynamic> toJson() => {
        "name": name,
        "description": description,
        "homepage": homepage,
        "main": main,
        "types": types,
        "module": module,
        "exports": exports.toJson(),
        "version": version,
        "engines": engines.toJson(),
        "maintainers": List<dynamic>.from(maintainers.map((x) => x.toJson())),
        "repository": repository.toJson(),
        "license": license,
        "scripts": scripts.toJson(),
        "bin": bin.toJson(),
    };
}

class Bin {
    String acorn;

    Bin({
        required this.acorn,
    });

    factory Bin.fromJson(Map<String, dynamic> json) => Bin(
        acorn: json["acorn"],
    );

    Map<String, dynamic> toJson() => {
        "acorn": acorn,
    };
}

class Engines {
    String node;

    Engines({
        required this.node,
    });

    factory Engines.fromJson(Map<String, dynamic> json) => Engines(
        node: json["node"],
    );

    Map<String, dynamic> toJson() => {
        "node": node,
    };
}

class Exports {
    List<dynamic> empty;
    String packageJson;

    Exports({
        required this.empty,
        required this.packageJson,
    });

    factory Exports.fromJson(Map<String, dynamic> json) => Exports(
        empty: List<dynamic>.from(json["."].map((x) => x)),
        packageJson: json["./package.json"],
    );

    Map<String, dynamic> toJson() => {
        ".": List<dynamic>.from(empty.map((x) => x)),
        "./package.json": packageJson,
    };
}

